// Validate required fields
const required = ['schoolName', 'className', 'subject', 'dayOfWeek', 'startTime', 'endTime', 'teacherEmail'];

for (const field of required) {
  if (!$input.first().json[field]) {
    throw new Error(`Missing required field: ${field}`);
  }
}

// Validate day of week
const validDays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday', 'Sunday'];
if (!validDays.includes($input.first().json.dayOfWeek)) {
  throw new Error('Invalid day of week');
}

// Validate time format (HH:MM)
const timeRegex = /^([0-1]?[0-9]|2[0-3]):[0-5][0-9]$/;
if (!timeRegex.test($input.first().json.startTime) || !timeRegex.test($input.first().json.endTime)) {
  throw new Error('Invalid time format. Use HH:MM');
}

// Add timestamp
const data = $input.first().json;
data.createdAt = new Date().toISOString();
data.updatedAt = data.createdAt;

return [{ json: data }];

